  1	import * as React from 'react';
  2	import { SummaryTable, SummaryTableRenderer } from './BaseTable';
  3	import { IRow, ISortBy, SortByDirection } from '@patternfly/react-table';
  4	import { ClusterSummary } from '../../../types/IstioObjects';
  5	import { ActiveFilter, FILTER_ACTION_APPEND, FilterType, AllFilterTypes } from '../../../types/Filters';
  6	import { SortField } from '../../../types/SortFilters';
  7	import { Namespace } from '../../../types/Namespace';
  8	import { defaultFilter, istioConfigLink, serviceLink } from '../../../helpers/EnvoyHelpers';
  9	import { Tooltip } from '@patternfly/react-core';
 10	import { PFColors } from 'components/Pf/PfColors';
 11	import { KialiIcon } from 'config/KialiIcon';
 12	import { kialiStyle } from 'styles/StyleUtils';
 13	import { isParentKiosk } from '../../Kiosk/KioskActions';
 14	import { SortableTh } from 'components/Table/SimpleTable';
 15	import { t } from 'utils/I18nUtils';
 16	import { dicTypeToGVK, gvkType } from '../../../types/IstioConfigList';
 17	
 18	export class ClusterTable implements SummaryTable {
 19	  kiosk: string;
 20	  namespace: string;
 21	  namespaces: Namespace[] | undefined;
 22	  sortingDirection: 'asc' | 'desc';
 23	  sortingIndex: number;
 24	  summaries: ClusterSummary[];
 25	
 26	  constructor(summaries: ClusterSummary[], sortBy: ISortBy, namespaces: Namespace[], namespace: string, kiosk: string) {
 27	    this.summaries = summaries;
 28	    this.sortingIndex = sortBy.index ?? 0;
 29	    this.sortingDirection = sortBy.direction ?? SortByDirection.asc;
 30	    this.namespaces = namespaces;
 31	    this.namespace = namespace;
 32	    this.kiosk = kiosk;
 33	  }
 34	
 35	  availableFilters = (): FilterType[] => {
 36	    return [
 37	      {
 38	        category: t('FQDN'),
 39	        placeholder: t('FQDN'),
 40	        filterType: AllFilterTypes.text,
 41	        action: FILTER_ACTION_APPEND,
 42	        filterValues: []
 43	      },
 44	      {
 45	        category: t('Port'),
 46	        placeholder: t('Port'),
 47	        filterType: AllFilterTypes.text,
 48	        action: FILTER_ACTION_APPEND,
 49	        filterValues: []
 50	      },
 51	      {
 52	        category: t('Subset'),
 53	        placeholder: t('Subset'),
 54	        filterType: AllFilterTypes.text,
 55	        action: FILTER_ACTION_APPEND,
 56	        filterValues: []
 57	      },
 58	      {
 59	        category: t('Direction'),
 60	        placeholder: t('Direction'),
 61	        filterType: AllFilterTypes.select,
 62	        action: FILTER_ACTION_APPEND,
 63	        filterValues: [
 64	          { id: 'inbound', title: t('inbound') },
 65	          { id: 'outbound', title: t('outbound') }
 66	        ]
 67	      }
 68	    ];
 69	  };
 70	
 71	  filterMethods = (): { [filter_id: string]: (entry: ClusterSummary, filter: ActiveFilter) => boolean } => {
 72	    return {
 73	      FQDN: (entry: ClusterSummary, filter: ActiveFilter): boolean => {
 74	        return [entry.service_fqdn.service, entry.service_fqdn.namespace, entry.service_fqdn.cluster]
 75	          .join('.')
 76	          .includes(filter.value);
 77	      },
 78	      Port: (entry: ClusterSummary, filter: ActiveFilter): boolean => {
 79	        return entry.port.toString().includes(filter.value);
 80	      },
 81	      Subset: (entry: ClusterSummary, filter: ActiveFilter): boolean => {
 82	        return entry.subset.toString().includes(filter.value);
 83	      },
 84	      Direction: (entry: ClusterSummary, filter: ActiveFilter): boolean => {
 85	        return entry.direction.toString().includes(filter.value);
 86	      }
 87	    };
 88	  };
 89	
 90	  sortFields = (): SortField<ClusterSummary>[] => {
 91	    return [
 92	      {
 93	        id: 'fqdn',
 94	        title: 'FQDN',
 95	        isNumeric: false,
 96	        param: 'fqdn',
 97	        compare: (a, b) => {
 98	          return [a.service_fqdn.service, a.service_fqdn.namespace, a.service_fqdn.cluster]
 99	            .join('.')
100	            .localeCompare([b.service_fqdn.service, b.service_fqdn.namespace, b.service_fqdn.cluster].join('.'));
101	        }
102	      },
103	      {
104	        id: 'port',
105	        title: 'Port',
106	        isNumeric: true,
107	        param: 'port',
108	        compare: (a, b) => {
109	          return a.port - b.port;
110	        }
111	      },
112	      {
113	        id: 'subset',
114	        title: 'Subset',
115	        isNumeric: false,
116	        param: 'subset',
117	        compare: (a, b) => {
118	          return a.subset.localeCompare(b.subset);
119	        }
120	      },
121	      {
122	        id: 'direction',
123	        title: 'Direction',
124	        isNumeric: false,
125	        param: 'direction',
126	        compare: (a, b) => {
127	          return a.direction.localeCompare(b.direction);
128	        }
129	      },
130	      {
131	        id: 'type',
132	        title: 'Type',
133	        isNumeric: false,
134	        param: 'type',
135	        compare: (a, b) => {
136	          return a.type.localeCompare(b.type);
137	        }
138	      },
139	      {
140	        id: 'dr',
141	        title: 'Destination Rule',
142	        isNumeric: true,
143	        param: 'dr',
144	        compare: (a, b) => {
145	          return a.destination_rule.localeCompare(b.destination_rule);
146	        }
147	      }
148	    ];
149	  };
150	
151	  render_cluster_type = (): React.ReactNode => {
152	    return (
153	      <ul className={kialiStyle({ textAlign: 'left' })}>
154	        <li>
155	          <b>STATIC</b>: Static is the simplest service discovery type. The configuration explicitly specifies the
156	          resolved network name (IP address/port, unix domain socket, etc.) of each upstream host.
157	        </li>
158	        <li>
159	          <b>STRICT_DNS</b>: Envoy will continuously and asynchronously resolve the specified DNS targets
160	        </li>
161	        <li>
162	          <b>LOGICAL_DNS</b>: Logical DNS uses a similar asynchronous resolution mechanism to strict DNS. However,
163	          instead of strictly taking the results of the DNS query and assuming that they comprise the entire upstream
164	          cluster, a logical DNS cluster only uses the first IP address returned when a new connection needs to be
165	          initiated
166	        </li>
167	        <li>
168	          <b>EDS</b>: The endpoint discovery service is a xDS management server based on gRPC or REST-JSON API server
169	          used by Envoy to fetch cluster members.{' '}
170	        </li>
171	        <li>
172	          <b>ORIGINAL_DST</b>: Original destination cluster can be used when incoming connections are redirected to
173	          Envoy either via an iptables REDIRECT or TPROXY target or with Proxy Protocol
174	        </li>
175	      </ul>
176	    );
177	  };
178	
179	  head = (): SortableTh[] => {
180	    return [
181	      {
182	        title: 'Service FQDN',
183	        sortable: true,
184	        info: { tooltip: <>Fully Qualified Domain Name</> }
185	      },
186	      {
187	        title: 'Port',
188	        sortable: true
189	      },
190	      {
191	        title: 'Subset',
192	        sortable: true
193	      },
194	      {
195	        title: 'Direction',
196	        sortable: true,
197	        info: {
198	          tooltip: (
199	            <ul className={kialiStyle({ textAlign: 'left' })}>
200	              <li>
201	                <b>inbound</b>: The inbound cluster events are the events that come into a node. These cluster events
202	                come from another node and enter other nodes.
203	              </li>
204	              <li>
205	                <b>outbound</b>: The outbound cluster events are the events that go out of a node. These cluster events
206	                are produced and sent from a node to other nodes.
207	              </li>
208	            </ul>
209	          )
210	        }
211	      },
212	      {
213	        title: 'Type',
214	        sortable: true,
215	        info: { tooltip: this.render_cluster_type() }
216	      },
217	      {
218	        title: 'DestinationRule',
219	        sortable: true
220	      }
221	    ];
222	  };
223	
224	  resource = (): string => 'clusters';
225	
226	  setSorting = (columnIndex: number, direction: 'asc' | 'desc'): void => {
227	    this.sortingIndex = columnIndex;
228	    this.sortingDirection = direction;
229	  };
230	
231	  sortBy = (): ISortBy => {
232	    return {
233	      index: this.sortingIndex,
234	      direction: this.sortingDirection ?? 'asc'
235	    };
236	  };
237	
238	  tooltip = (): React.ReactNode => {
239	    return (
240	      <Tooltip
241	        content={
242	          <div className={kialiStyle({ textAlign: 'left' })}>
243	            Group of logically similar upstream hosts that Envoy connects to. (All the hosts that envoy manage traffic)
244	          </div>
245	        }
246	      >
247	        <KialiIcon.Help className={kialiStyle({ width: '14px', height: '14px', color: PFColors.Info })} />
248	      </Tooltip>
249	    );
250	  };
251	
252	  rows(): IRow[] {
253	    const parentKiosk = isParentKiosk(this.kiosk);
254	    return this.summaries
255	      .filter((value: ClusterSummary): boolean => {
256	        return defaultFilter(value, this.filterMethods());
257	      })
258	      .sort((a: ClusterSummary, b: ClusterSummary): number => {
259	        const sortField = this.sortFields().find((value: SortField<ClusterSummary>): boolean => {
260	          return value.id === this.sortFields()[this.sortingIndex].id;
261	        });
262	
263	        return this.sortingDirection === 'asc' ? sortField!.compare(a, b) : sortField!.compare(b, a);
264	      })
265	      .map(
266	        (value: ClusterSummary): IRow => {
267	          return {
268	            cells: [
269	              serviceLink(value.service_fqdn, this.namespaces, this.namespace, false, parentKiosk),
270	              value.port,
271	              value.subset,
272	              value.direction,
273	              value.type,
274	              istioConfigLink(value.destination_rule, dicTypeToGVK[gvkType.DestinationRule])
275	            ]
276	          };
277	        }
278	      );
279	  }
280	}
281	
282	export const ClusterSummaryTable = SummaryTableRenderer<ClusterTable>();

